 1	import * as React from 'react';
 2	import { MenuToggle, MenuToggleElement, Select, SelectProps } from '@patternfly/react-core';
 3	
 4	type SimpleSelectProps = Omit<Omit<Omit<Omit<SelectProps, 'isOpen'>, 'onSelect'>, 'onOpenChange'>, 'toggle'> & {
 5	  onOpenChange?: (isOpen: boolean) => void;
 6	  onSelect?: (value?: string | number) => void;
 7	};
 8	
 9	export const SimpleSelect: React.FC<SimpleSelectProps> = (props: SimpleSelectProps) => {
10	  const [isOpen, setIsOpen] = React.useState(false);
11	
12	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
13	    <MenuToggle ref={toggleRef} onClick={() => setIsOpen(!isOpen)} isExpanded={isOpen}>
14	      {props.selected}
15	    </MenuToggle>
16	  );
17	
18	  return (
19	    <Select
20	      {...props}
21	      toggle={toggle}
22	      onOpenChange={isOpen => {
23	        setIsOpen(isOpen);
24	
25	        if (props.onOpenChange) {
26	          props.onOpenChange(isOpen);
27	        }
28	      }}
29	      onSelect={(_event?: React.MouseEvent<Element, MouseEvent>, value?: string | number) => {
30	        setIsOpen(false);
31	        if (props.onSelect) {
32	          props.onSelect(value);
33	        }
34	      }}
35	      isOpen={isOpen}
36	    >
37	      {props.children}
38	    </Select>
39	  );
40	};

